[{"location":"#KeldyshContraction.jl","page":"Home","title":"KeldyshContraction.jl","text":"","category":"section"},{"location":"","page":"Home","title":"Home","text":"(Image: codecov)","category":"page"},{"location":"","page":"Home","title":"Home","text":"(Image: Code Style: Blue) (Image: Aqua QA) (Image: JET)","category":"page"},{"location":"","page":"Home","title":"Home","text":"KeldyshContraction.jl is a package for the symbolic derivation of the two-point correlator diagrams  in Keldysh-Schwinger field theory. The symbolic quantum field theory algebra is omplemented using SymbolicUtils.jl and TermInterface.jl of the JuliaSymbolic ecosystem. The typesystem has been heavily inspired by the second quantization algebra defined in QuantumCumulants.jl.","category":"page"},{"location":"API/","page":"API","title":"API","text":"CollapsedDocStrings = true","category":"page"},{"location":"API/#API","page":"API","title":"API","text":"","category":"section"},{"location":"API/","page":"API","title":"API","text":"Modules = [KeldyshContraction]\nPrivate = false\nOrder   = [:function, :type]","category":"page"},{"location":"API/#KeldyshContraction.Create","page":"API","title":"KeldyshContraction.Create","text":"Create <: QSym\n\nBosonic field representing the quantum field creation operator.\n\n\n\n\n\n","category":"type"},{"location":"API/#KeldyshContraction.Destroy","page":"API","title":"KeldyshContraction.Destroy","text":"Destroy <: QSym\n\nBosonic field representing the quantum field annihilation operator.\n\n\n\n\n\n","category":"type"}]
